Bash(node --input-type=module -e "
import { schemaToZod } from './dist/zod.js';
import { schemaToValibot } from './dist/valibot.js';
import { schemaToEffect } from './dist/effect.js';
import { schemaToTypebox } from './dist/typebox.js';
import { schemaToArktype } from './dist/arktype.js';

const schema = {
  title: 'User',
  type: 'object',
  properties: {
    name: { type: 'string' },
    email: { type: 'string', format: 'email' },
    age: { type: 'integer', minimum: 0 }
  },
  required: ['name', 'email']
};

console.log\('=== Zod \(no exportType\) ==='\);
console.log\(schemaToZod\(schema, { exportType: false }\)\);
console.log\('\\n=== Zod \(with exportType\) ==='\);
console.log\(schemaToZod\(schema\)\);
console.log\('\\n=== Valibot \(no exportType\) ==='\);
console.log\(schemaToValibot\(schema, { exportType: false }\)\);
console.log\('\\n=== Valibot \(with exportType\) ==='\);
console.log\(schemaToValibot\(schema\)\);
console.log\('\\n=== Effect \(no exportType\) ==='\);
console.log\(schemaToEffect\(schema, { exportType: false }\)\);
console.log\('\\n=== Effect \(with exportType\) ==='\);
console.log\(schemaToEffect\(schema\)\);
console.log\('\\n=== TypeBox \(no exportType\) ==='\);
console.log\(schemaToTypebox\(schema, { exportType: false }\)\);
console.log\('\\n=== TypeBox \(with exportType\) ==='\);
console.log\(schemaToTypebox\(schema\)\);
console.log\('\\n=== Arktype \(no exportType\) ==='\);
console.log\(schemaToArktype\(schema, { exportType: false }\)\);
console.log\('\\n=== Arktype \(with exportType\) ==='\);
console.log\(schemaToArktype\(schema\)\);
")
